"use client";
import React, { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { MapPin, ArrowRight, Home } from "lucide-react";

// 🔥 TOP 10 CITIES LIST (Inhi cities ka data dikhega)
const CITIES = [
  "Bilaspur",
  "Raipur",
  "Durg",
  "Bhilai",
  "Korba",
  "Raigarh",
  "Jagdalpur",
  "Ambikapur",
  "Rajnandgaon",
  "Dhamtari"
];

export default function HousePage() {
  const router = useRouter();

  return (
    <div className="min-h-screen bg-[#F8FAFC] pb-20">
      
      {/* --- HEADER --- */}
      <div className="bg-white p-6 sticky top-0 z-30 shadow-sm border-b border-gray-100">
        <div className="flex items-center gap-2">
          <button onClick={() => router.back()} className="p-2 bg-gray-100 rounded-full hover:bg-gray-200">
            <ArrowRight className="rotate-180" size={20} />
          </button>
          <h1 className="text-2xl font-black text-gray-900 tracking-tight flex items-center gap-2">
            <Home className="text-blue-600" /> Residential Houses
          </h1>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 md:px-8 mt-6 space-y-12">
        {/* --- HAR CITY KE LIYE SECTION GENERATE HOGA --- */}
        {CITIES.map((city, index) => (
          <CitySection key={index} city={city} router={router} />
        ))}
      </div>

    </div>
  );
}

// 🧩 REUSABLE COMPONENT: Har City ka alag section sambhalega
const CitySection = ({ city, router }) => {
  const [properties, setProperties] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        // 🔥 Database se data lana (Filter: City + Category=House)
        const res = await fetch(`/api/properties?district=${city}&cat=House&limit=10`);
        const data = await res.json();
        
        // API response handle karna (array check)
        const list = data.properties || data;
        if (Array.isArray(list)) {
          setProperties(list);
        }
      } catch (err) {
        console.error(`Error fetching ${city}:`, err);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [city]);

  // Agar data nahi hai us city ka, to section mat dikhao
  if (!loading && properties.length === 0) return null;

  return (
    <div className="flex flex-col gap-4">
      
      {/* Section Header */}
      <div className="flex justify-between items-end px-2">
        <div>
          <h2 className="text-xl md:text-2xl font-black text-gray-900">In {city}</h2>
          <p className="text-xs text-gray-500 font-bold uppercase tracking-widest mt-1">Latest Listings</p>
        </div>
        <button 
          onClick={() => router.push(`/search?district=${city}&cat=House`)}
          className="text-blue-600 font-bold text-sm flex items-center gap-1 hover:underline"
        >
          See All <ArrowRight size={16} />
        </button>
      </div>

      {/* 🔥 MAGIC LAYOUT: 
          - Mobile: flex + overflow-x-auto (Horizontal Scroll)
          - Desktop: grid + grid-cols-4 (4 per row)
      */}
      <div className="flex md:grid md:grid-cols-3 lg:grid-cols-4 gap-5 overflow-x-auto pb-6 snap-x snap-mandatory hide-scrollbar px-2">
        
        {loading ? (
          // Skeleton Loader (Jab tak data aa raha hai)
          [1, 2, 3, 4].map((i) => (
            <div key={i} className="min-w-[280px] md:min-w-0 h-64 bg-gray-200 rounded-2xl animate-pulse"></div>
          ))
        ) : (
          properties.map((item) => (
            <div 
              key={item._id}
              onClick={() => router.push(`/properties/${item._id}`)} // Detail page link
              className="
                group min-w-[280px] md:min-w-0 w-[85vw] md:w-auto 
                bg-white rounded-3xl border border-gray-100 shadow-sm 
                hover:shadow-xl transition-all duration-300 cursor-pointer 
                snap-center flex flex-col overflow-hidden relative
              "
            >
              {/* Image */}
              <div className="h-44 md:h-48 relative overflow-hidden">
                <img 
                  src={item.images?.[0] || "/placeholder.jpg"} 
                  alt={item.title} 
                  className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700"
                />
                <div className="absolute top-3 left-3 bg-black/60 backdrop-blur-md text-white text-[10px] font-bold px-3 py-1 rounded-full uppercase">
                  {item.cat}
                </div>
                <div className="absolute bottom-3 right-3 bg-white px-3 py-1 rounded-lg text-xs font-black shadow-lg">
                  ₹ {item.price?.toLocaleString('en-IN')}
                </div>
              </div>

              {/* Content */}
              <div className="p-4 flex flex-col gap-2">
                <h3 className="font-bold text-gray-900 truncate text-lg">{item.title}</h3>
                
                <div className="flex items-center gap-1 text-gray-500 text-sm font-medium">
                  <MapPin size={14} className="text-blue-500" />
                  <span className="truncate">{item.address || "Address hidden"}, {city}</span>
                </div>

                {/* Specs (Bed/Bath/Area) */}
                <div className="flex items-center justify-between mt-2 pt-3 border-t border-gray-100">
                   <div className="text-xs font-bold text-gray-400 bg-gray-50 px-2 py-1 rounded-md">
                      {item.details?.beds || 0} Beds
                   </div>
                   <div className="text-xs font-bold text-gray-400 bg-gray-50 px-2 py-1 rounded-md">
                      {item.details?.area || 0} Sqft
                   </div>
                </div>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};